// ============================================
// AuthModal Component - Login & Register
// ============================================

// ============================================
// AuthModal Component - Login & Register
// ============================================

import React, { useState } from 'react';
import { FiX, FiMail, FiLock, FiUser, FiEye, FiEyeOff, FiCheck } from 'react-icons/fi';
import { WiDaySunny } from 'react-icons/wi';
import { useAuth } from '../context/AuthContext';

// ---- LOGIN BENEFITS shown to the user ----
const LOGIN_BENEFITS = [
  { icon: '⭐', title: 'Save Favorite Cities', desc: 'Pin up to 10 cities for instant one-click access anytime' },
  { icon: '🕐', title: 'Search History', desc: 'Your last 10 searched cities remembered automatically' },
  { icon: '🤖', title: 'Personalized AI Tips', desc: 'AI recommendations tailored to your saved locations' },
  { icon: '🌙', title: 'Dark Mode Memory', desc: 'Your theme preference saved across sessions' },
  { icon: '🌡️', title: 'Unit Preferences', desc: 'Choose Celsius or Fahrenheit — remembered forever' },
  { icon: '📍', title: 'Quick Location Access', desc: 'Jump back to any saved city with a single tap' },
];

const AuthModal = ({ onClose }) => {
  const [mode, setMode] = useState('login'); // 'login' | 'register' | 'benefits'
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const { login, register } = useAuth();

  const handleChange = (e) => {
    setFormData(prev => ({ ...prev, [e.target.name]: e.target.value }));
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');

    try {
      if (mode === 'login') {
        const res = await login(formData.email, formData.password);
        setSuccess(res.message || 'Logged in successfully!');
        setTimeout(() => onClose(), 800);
      } else {
        if (!formData.name.trim()) {
          setError('Please enter your full name');
          setLoading(false);
          return;
        }
        if (formData.password.length < 6) {
          setError('Password must be at least 6 characters');
          setLoading(false);
          return;
        }
        const res = await register(formData.name, formData.email, formData.password);
        setSuccess(res.message || 'Account created!');
        setTimeout(() => onClose(), 800);
      }
    } catch (err) {
      // Show a helpful error message
      const msg = err.response?.data?.message || '';
      if (msg.toLowerCase().includes('invalid') || msg.toLowerCase().includes('password')) {
        setError('❌ Wrong email or password. Did you register yet? Click "Register" below!');
      } else if (msg.toLowerCase().includes('exists') || msg.toLowerCase().includes('duplicate')) {
        setError('This email is already registered. Try logging in instead.');
      } else if (!msg) {
        setError('Cannot reach the server. Make sure backend is running on port 5000.');
      } else {
        setError(msg);
      }
    } finally {
      setLoading(false);
    }
  };

  const switchMode = (newMode) => {
    setMode(newMode);
    setError('');
    setSuccess('');
    setFormData({ name: '', email: '', password: '' });
  };

  // ---- INPUT FIELD COMPONENT ----
  const InputField = ({ icon, name, type, placeholder }) => (
    <div className="relative group">
      <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-400 transition-colors text-lg">
        {icon}
      </div>
      <input
        type={name === 'password' ? (showPassword ? 'text' : 'password') : type}
        name={name}
        value={formData[name] || ''}
        onChange={handleChange}
        placeholder={placeholder}
        required
        autoComplete={name === 'password' ? 'current-password' : name === 'email' ? 'email' : 'name'}
        style={{
          WebkitTextFillColor: 'inherit',
          WebkitBoxShadow: '0 0 0px 1000px transparent inset',
          transition: 'background-color 5000s ease-in-out 0s'
        }}
        className="w-full pl-12 pr-12 py-4 rounded-2xl text-slate-800 dark:text-white placeholder-slate-400 dark:placeholder-slate-500 outline-none border-2 border-slate-200 dark:border-slate-600 focus:border-blue-400 dark:focus:border-blue-400 transition-all text-sm font-medium"
        style={{
          background: 'var(--input-bg)',
          WebkitTextFillColor: 'inherit',
        }}
      />
      {name === 'password' && (
        <button
          type="button"
          onClick={() => setShowPassword(!showPassword)}
          className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-blue-500 transition-colors"
        >
          {showPassword ? <FiEyeOff /> : <FiEye />}
        </button>
      )}
    </div>
  );

  // ---- BENEFITS PANEL ----
  if (mode === 'benefits') {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4"
        style={{ background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(12px)' }}>
        <div className="w-full max-w-lg rounded-3xl overflow-hidden shadow-2xl animate-slide-up"
          style={{ background: 'linear-gradient(135deg, #1e293b 0%, #0f172a 100%)', border: '1px solid rgba(148,163,184,0.15)' }}>

          {/* Header */}
          <div className="relative p-7 pb-5" style={{ background: 'linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%)' }}>
            <button onClick={onClose} className="absolute top-5 right-5 text-white/70 hover:text-white">
              <FiX className="text-xl" />
            </button>
            <div className="text-4xl mb-3">🔓</div>
            <h2 className="text-white text-2xl font-bold">Why Create an Account?</h2>
            <p className="text-blue-100 text-sm mt-1">Unlock these powerful features — completely FREE!</p>
          </div>

          {/* Benefits List */}
          <div className="p-6 grid grid-cols-1 gap-3">
            {LOGIN_BENEFITS.map((b, i) => (
              <div key={i} className="flex items-start gap-4 p-3 rounded-2xl hover:bg-white/5 transition-all">
                <div className="text-2xl mt-0.5 flex-shrink-0">{b.icon}</div>
                <div>
                  <p className="text-white font-semibold text-sm">{b.title}</p>
                  <p className="text-slate-400 text-xs mt-0.5">{b.desc}</p>
                </div>
                <FiCheck className="text-green-400 ml-auto mt-1 flex-shrink-0" />
              </div>
            ))}
          </div>

          {/* CTA Buttons */}
          <div className="px-6 pb-7 flex gap-3">
            <button onClick={() => switchMode('register')}
              className="flex-1 py-3.5 rounded-2xl text-white font-bold text-sm transition-all"
              style={{ background: 'linear-gradient(135deg, #3b82f6, #8b5cf6)' }}>
              Create Free Account
            </button>
            <button onClick={() => switchMode('login')}
              className="flex-1 py-3.5 rounded-2xl font-semibold text-sm border border-slate-600 text-slate-300 hover:bg-white/10 transition-all">
              Already have one? Login
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ---- LOGIN / REGISTER PANEL ----
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4"
      style={{ background: 'rgba(0,0,0,0.65)', backdropFilter: 'blur(12px)' }}>

      {/* Modal Card — different bg for light vs dark */}
      <div className="w-full max-w-md rounded-3xl shadow-2xl overflow-hidden animate-slide-up"
        style={{
          '--input-bg': 'var(--tw-prose-body, #f8fafc)',
          background: 'var(--modal-bg, #ffffff)',
        }}>

        {/* 
          We use inline styles here so the modal is visibly different
          in light vs dark mode since Tailwind dark: classes need the
          'dark' class on <html>, which the app handles via toggleDarkMode.
          As a fallback we use a fixed high-contrast design.
        */}
        <style>{`
          .auth-modal-card {
            background: #ffffff;
            color: #0f172a;
          }
          .dark .auth-modal-card {
            background: #0f172a;
            color: #f1f5f9;
          }
          .auth-input {
            background: #f1f5f9;
            color: #0f172a;
            border: 2px solid #e2e8f0;
          }
          .auth-input::placeholder { color: #94a3b8; }
          .dark .auth-input {
            background: #1e293b;
            color: #f1f5f9;
            border: 2px solid #334155;
          }
          .dark .auth-input::placeholder { color: #64748b; }
          .auth-input:focus { border-color: #3b82f6; outline: none; }
          .auth-label { color: #64748b; }
          .dark .auth-label { color: #94a3b8; }
          .auth-switch { color: #64748b; }
          .dark .auth-switch { color: #94a3b8; }
          .auth-divider { border-color: #e2e8f0; }
          .dark .auth-divider { border-color: #1e293b; }
        `}</style>

        <div className="auth-modal-card rounded-3xl">

          {/* Colorful Header Banner */}
          <div className="relative p-7 pb-6"
            style={{ background: 'linear-gradient(135deg, #1d4ed8 0%, #7c3aed 50%, #db2777 100%)' }}>
            <button onClick={onClose}
              className="absolute top-4 right-4 text-white/70 hover:text-white w-8 h-8 flex items-center justify-center rounded-full hover:bg-white/20 transition-all">
              <FiX className="text-lg" />
            </button>

            <WiDaySunny className="text-yellow-300 text-5xl mb-3" />
            <h2 className="text-white text-2xl font-bold">
              {mode === 'login' ? 'Welcome Back! 👋' : 'Create Account ✨'}
            </h2>
            <p className="text-blue-100 text-sm mt-1">
              {mode === 'login'
                ? 'Login to unlock all your saved cities & preferences'
                : 'Free forever — no credit card needed'}
            </p>

            {/* Benefits hint */}
            {mode === 'login' && (
              <button onClick={() => setMode('benefits')}
                className="mt-3 text-xs text-white/70 underline underline-offset-2 hover:text-white transition-colors">
                Why should I login? See all benefits →
              </button>
            )}
          </div>

          {/* Form Area */}
          <div className="p-7 pt-6">

            {/* Success Message */}
            {success && (
              <div className="mb-4 p-3 rounded-2xl text-sm text-center font-medium flex items-center justify-center gap-2"
                style={{ background: '#dcfce7', color: '#166534', border: '1px solid #bbf7d0' }}>
                <FiCheck /> {success}
              </div>
            )}

            {/* Error Message */}
            {error && (
              <div className="mb-4 p-4 rounded-2xl text-sm"
                style={{ background: '#fef2f2', color: '#dc2626', border: '1px solid #fecaca' }}>
                <p className="font-semibold mb-1">⚠️ Login Failed</p>
                <p className="text-xs leading-relaxed">{error}</p>
                {error.includes('Register') && (
                  <button onClick={() => switchMode('register')}
                    className="mt-2 text-xs font-bold underline" style={{ color: '#2563eb' }}>
                    → Click here to Register instead
                  </button>
                )}
              </div>
            )}

            {/* Not Registered Notice */}
            {mode === 'login' && (
              <div className="mb-4 p-3 rounded-xl text-xs"
                style={{ background: '#eff6ff', color: '#1d4ed8', border: '1px solid #bfdbfe' }}>
                💡 <strong>First time?</strong> You need to <button onClick={() => switchMode('register')} className="underline font-bold">Register first</button> before you can login.
              </div>
            )}

            {/* Form */}
            <form onSubmit={handleSubmit} className="space-y-4">
              {mode === 'register' && (
                <div className="relative">
                  <FiUser className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-base" />
                  <input
                    type="text" name="name" value={formData.name}
                    onChange={handleChange} placeholder="Your full name" required
                    className="auth-input w-full pl-12 pr-4 py-4 rounded-2xl text-sm font-medium transition-all"
                  />
                </div>
              )}

              <div className="relative">
                <FiMail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-base" />
                <input
                  type="email" name="email" value={formData.email}
                  onChange={handleChange} placeholder="Email address" required
                  className="auth-input w-full pl-12 pr-4 py-4 rounded-2xl text-sm font-medium transition-all"
                />
              </div>

              <div className="relative">
                <FiLock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-base" />
                <input
                  type={showPassword ? 'text' : 'password'}
                  name="password" value={formData.password}
                  onChange={handleChange}
                  placeholder={mode === 'register' ? 'Password (min 6 characters)' : 'Your password'}
                  required className="auth-input w-full pl-12 pr-12 py-4 rounded-2xl text-sm font-medium transition-all"
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-blue-500 transition-colors">
                  {showPassword ? <FiEyeOff /> : <FiEye />}
                </button>
              </div>

              <button
                type="submit" disabled={loading}
                className="w-full py-4 rounded-2xl text-white font-bold text-base transition-all disabled:opacity-60 mt-1"
                style={{ background: loading ? '#6b7280' : 'linear-gradient(135deg, #2563eb, #7c3aed)' }}>
                {loading ? (
                  <span className="flex items-center justify-center gap-2">
                    <span className="w-4 h-4 border-2 border-white/40 border-t-white rounded-full animate-spin inline-block" />
                    {mode === 'login' ? 'Logging in...' : 'Creating account...'}
                  </span>
                ) : (
                  mode === 'login' ? '🔓 Login to My Account' : '🚀 Create My Free Account'
                )}
              </button>
            </form>

            {/* Divider */}
            <div className="flex items-center gap-3 my-5">
              <div className="flex-1 border-t auth-divider" />
              <span className="auth-label text-xs">or</span>
              <div className="flex-1 border-t auth-divider" />
            </div>

            {/* Switch Mode */}
            <p className="text-center auth-switch text-sm">
              {mode === 'login' ? "New here? " : "Already registered? "}
              <button
                onClick={() => switchMode(mode === 'login' ? 'register' : 'login')}
                className="font-bold transition-colors"
                style={{ color: '#2563eb' }}>
                {mode === 'login' ? '→ Create Free Account' : '→ Login Instead'}
              </button>
            </p>

            {mode === 'login' && (
              <p className="text-center mt-3">
                <button onClick={() => setMode('benefits')}
                  className="text-xs auth-label hover:underline">
                  What do I get by logging in?
                </button>
              </p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthModal;
